+                                .ok_or(PersistError::InvalidFrame)?;
+                            cursor += c2;
+                            fields.push((f, v));
+                        }
+                        RdbValue::Hash(fields)
+                    }
+                    RDB_TYPE_ZSET => {
+                        let (count, c) = rdb_decode_length(&data[cursor..])
+                            .ok_or(PersistError::InvalidFrame)?;
+                        cursor += c;
+                        let mut members = Vec::with_capacity(count);
+                        for _ in 0..count {
+                            let (m, c) = rdb_decode_string(&data[cursor..])
+                                .ok_or(PersistError::InvalidFrame)?;
+                            cursor += c;
+                            if cursor + 8 > data.len() {
