+                    key,
+                    value,
+                    expire_ms: pending_expire_ms.take(),
+                });
+            }
+            _ => {
+                // Unknown type — skip this entry (fail-closed for safety)
+                return Err(PersistError::InvalidFrame);
+            }
+        }
+    }
+
+    Ok((entries, aux))
+}
